#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int a, b, c, d, e, f, L, R;
        scanf("%d %d %d %d %d %d %d %d", &a, &b, &c, &d, &e, &f, &L, &R);
        if (a > L || b > R || d > L || e > R) {
            printf("-1\n");
        } else {
            printf("0 %d\n", b);
            printf("%d %d\n", a, 0);
            printf("0 0\n");
            printf("%d %d\n", L, e);
            printf("%d %d\n", L, 0);
            printf("%d %d\n", L + d, 0);
        }
    }
    return 0;
}

